DELETE FROM booking_items
WHERE seat_id IN (
    SELECT id
    FROM seats
    WHERE hall_id IN (
        '30000000-0000-0000-0000-000000000001',
        '30000000-0000-0000-0000-000000000002'
    )
);

DELETE FROM session_seats
WHERE session_id IN (
    '50000000-0000-0000-0000-000000000001',
    '50000000-0000-0000-0000-000000000002',
    '50000000-0000-0000-0000-000000000003',
    '50000000-0000-0000-0000-000000000004'
);

DELETE FROM payments
WHERE booking_id IN (
    SELECT id
    FROM bookings
    WHERE session_id IN (
        '50000000-0000-0000-0000-000000000001',
        '50000000-0000-0000-0000-000000000002',
        '50000000-0000-0000-0000-000000000003',
        '50000000-0000-0000-0000-000000000004'
    )
);

DELETE FROM bookings
WHERE session_id IN (
    '50000000-0000-0000-0000-000000000001',
    '50000000-0000-0000-0000-000000000002',
    '50000000-0000-0000-0000-000000000003',
    '50000000-0000-0000-0000-000000000004'
);

DELETE FROM sessions
WHERE id IN (
    '50000000-0000-0000-0000-000000000001',
    '50000000-0000-0000-0000-000000000002',
    '50000000-0000-0000-0000-000000000003',
    '50000000-0000-0000-0000-000000000004'
);

DELETE FROM seats
WHERE hall_id IN (
    '30000000-0000-0000-0000-000000000001',
    '30000000-0000-0000-0000-000000000002'
);

DELETE FROM halls
WHERE id IN (
    '30000000-0000-0000-0000-000000000001',
    '30000000-0000-0000-0000-000000000002'
);

DELETE FROM event_external_links
WHERE event_id IN (
    '40000000-0000-0000-0000-000000000001',
    '40000000-0000-0000-0000-000000000002',
    '40000000-0000-0000-0000-000000000003'
);

DELETE FROM events
WHERE id IN (
    '40000000-0000-0000-0000-000000000001',
    '40000000-0000-0000-0000-000000000002',
    '40000000-0000-0000-0000-000000000003'
);

DELETE FROM venues
WHERE id = '20000000-0000-0000-0000-000000000001'
  AND NOT EXISTS (SELECT 1 FROM halls WHERE venue_id = '20000000-0000-0000-0000-000000000001')
  AND NOT EXISTS (SELECT 1 FROM events WHERE venue_id = '20000000-0000-0000-0000-000000000001');
